// Helpers
// ---------------------------------------------------------------------------

/** Invoke git with explicit args 鈥?no shell interpolation. */
function git(cwd: string, ...args: string[]): string {
  return execFileSync('git', args, { cwd, stdio: 'pipe' }).toString()
}

