    ? [{
        tag: 'button',
        text: { content: 'View Report', tag: 'plain_text' },
        url: reportUrl,
        type: 'primary',
      }]
    : []

  return {
    msg_type: 'interactive',
    card: {
      header: {
        title: { content: 'MemoryTree Report Updated', tag: 'plain_text' },
        template: 'blue',
